INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 112, 106431, 0, 10, 112029, 0.5, "ランドソルを囲む壁に絵を？\nふぅん、楽しそうね。\nここに描けばいいのかしら？", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 112, 112029, "", "", 112030, "", "", "", "", 91);
