INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 112, 118511, 0, 10, 112034, 0.5, "はい。ここから始めて、\nランドソルの壁をぐるっと一周\n絵でいっぱいにしたいんです。", 1, 0, 11);
