INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 112, 106431, 0, 10, 112039, 0.5, "え？　ランドソルの壁を……\nぐるっと一周？", 1, 0, 11);
