INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 5012, 100211, 0, 10, 5012018, 0.5, "うん、いい感じに描けたね！\n……でもこの絵って、ずっと\nランドソルに残るんだよね？\nそ、それはちょっと恥ずかしいかも……", 1, 0, 11);
