INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 8612, 105911, 0, 10, 8612022, 0.5, "ふふ、こうしてみなさまと一緒に\n絵を描くというのもまた\n楽しいものでございますね。", 1, 0, 11);
