INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_smile_loop_L", 14112, 102711, 0.2, 0, 14112038, "", "wac_talk_smile_in_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 14112, "vo_wac_220705", "", 0, 14112039, "", "vo_wac_220705_003", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112, 102711, 0, 10, 14112040, 0.5, "クスクス……私は見ていましたよ。\nアンナさん、あなたがいそいそと\n後ろで道具を片づけているのを……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112, 0, "", "", 14112041, "", "", "", "", 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112, 102711, 0.2, 1, 14112042, "", "wac_idle_smile_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_doya_loop_L", 14112, 105611, 0.2, 0, 14112043, "", "wac_talk_doya_in_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 14112, "vo_wac_220705", "", 0, 14112044, "", "vo_wac_220705_004", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112, 105611, 0, 10, 14112045, 0.5, "はは、そりゃ助かった。\nお前さん、物言いは突飛だが、\nそういうところにはよく気が回るねえ。\nいい子じゃないか。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112, 0, "", "", 14112046, "", "", "", "", 91);
