INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112, 100911, 0.2, 1, 14112048, "", "wac_talk_anger", "", "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 14112, "vo_wac_220705", "", 0, 14112049, "", "vo_wac_220705_005", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112, 100911, 0, 10, 14112050, 0.5, "なっ、いい子とか言うなぁ！\nて、手がすいたからやっただけで、\nそこはせめて全知全能と……\nうぅ、生暖かい目で見るなぁっ！", 1, 0, 11);
