INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14312, 101711, 0, 10, 14312022, 0.5, "ふふ、絵を描くのって楽しいさ～！\n描いても描いても飽きないし……\n歌って踊ればもっと楽しくなるさ～！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14312, 0, "", "", 14312023, "", "", "", "", 91);
