INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14312, 104311, 0, 10, 14312027, 0.5, "バ、バカ！　絵筆持ったまま\n踊るなって！　尻尾に\n絵の具がつくと落とすの大変なんだよ！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14312, 0, "", "", 14312028, "", "", "", "", 91);
