INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14312, 101011, 0, 10, 14312032, 0.5, "うちもこの間、それやってしもうたなぁ。\nふふ、でも安心しておくれやす。\nきれいに落とす方法、\nうちが教えてあげますえ。", 1, 0, 11);
