INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14712, 101311, 0, 10, 14712031, 0.5, "さすがだね、アンナたそ！\nけど私も負けないよ～！\n芸術の神が舞い降りたかのような\nこの完成度、ぜひご照覧あれ～！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14712, 0, "", "", 14712032, "", "", "", "", 91);
