INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14712, 102711, 0, 10, 14712036, 0.5, "なにをバカなことを……\nあなた様への愛をありったけ\n詰め込んだ、私の絵こそが\n一番の傑作に決まってます……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14712, 0, "", "", 14712037, "", "", "", "", 91);
