INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112, 106811, 0, 10, 16112018, 0.5, "ふぅ……たまにはこうして\n童心に帰って一心に絵を描く\nっていうのもいいものだねぇ……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16112, 0, "", "", 16112019, "", "", "", "", 91);
