INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 16112, "vo_wac_220725", "", 0, 16112022, "", "vo_wac_220725_001", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112, 101111, 0, 10, 16112023, 0.5, "うわあ！　マスターってば\n絵も上手なんですね！　でも\n言い方がお婆ちゃんみたいですよ？\nなるほど、これが亀の甲羅で逃避行！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16112, 0, "", "", 16112024, "", "", "", "", 91);
