INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_smile_loop_L", 16112, 104911, 0.2, 0, 16112026, "", "wac_talk_smile_in_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 16112, "vo_wac_220725", "", 0, 16112027, "", "vo_wac_220725_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112, 104911, 0, 10, 16112028, 0.5, "リノちゃん、こーら☆\nそんな言い方失礼だよ？\nマスターはいつも忙しくて\n大変なんだから。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16112, 0, "", "", 16112029, "", "", "", "", 91);
