INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112, 106811, 0, 10, 16112033, 0.5, "ごめんごめん少し感慨深くてさ。\n確かに老け込むには早いね。\nなにせまだまだこの世界には\n解き明かすべき謎がいっぱいだ。", 1, 0, 11);
