INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412, 103011, 0, 10, 16412030, 0.5, "シュバッ！　シュバババッ！\n色塗りはワタシにお任せデース！\nこの絵筆二刀流で、瞬く間に\nカラフルにしてみせマース！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16412, 0, "", "", 16412031, "", "", "", "", 91);
