INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412, 100811, 0, 10, 16412035, 0.5, "絵の下書きはボクに任せて。\nすべての美しさの源になる存在……\nそれがボクだからね！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16412, 0, "", "", 16412036, "", "", "", "", 91);
