INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412, 104511, 0, 10, 16412040, 0.5, "それをクウカがなぞって……\nはぁっ、もし皆さんの作業を\n台無しにしちゃったらって思うと……\nす、すごく……興奮しますぅ……！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16412, 0, "", "", 16412041, "", "", "", "", 91);
