INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412, 105511, 0, 10, 16412045, 0.5, "あっ、道具のお片づけは\n私がしておきました……\nこういう地味な作業でも、\nお役に立ててるといいんですけど……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16412, 0, "", "", 16412046, "", "", "", "", 91);
