INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 16612, "vo_wac_220730", "", 0, 16612040, "", "vo_wac_220730_003", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612, 105111, 0, 10, 16612041, 0.5, "まったくもう……\nみんなして絵の具まみれじゃない。\nって、あら？　この赤いのは……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612, 0, "", "", 16612042, "", "", "", "", 91);
