INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612, 105611, 0, 10, 16612046, 0.5, "ふふ、そういうアンタも、\nほっぺに絵の具がついてるじゃないか。\nほら、きれいにしてやるから\nそこに並びな、アンタたち。", 1, 0, 11);
