INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17612, 104311, 0, 10, 17612022, 0.5, "よーし、ざっとこんなもんだろ！\nこういうのはあたし向きじゃないと\n思ってたんだが、慣れてくると\n案外楽しいもんだな♪", 1, 0, 11);
