INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17612, 101411, 0, 10, 17612027, 0.5, "芸術という名の頭脳労働でありながら、\n程よく体を動かせて運動にもなるしね。\n名探偵の余暇の活動としても、\n最適解だと思うよ♪", 1, 0, 11);
