INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17812, 103711, 0, 10, 17812022, 0.5, "これで担当分はおしまいかな？\n剣術も芸術も、雑念を振り払い、\n一意専心に取り組むのが\nうまくいくコツな気がするよ。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 17812, 0, "", "", 17812023, "", "", "", "", 91);
