INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_sad_loop_L", 17812, 104711, 0.2, 0, 17812025, "", "wac_talk_sad_in_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 17812, "vo_wac_220811", "", 0, 17812026, "", "vo_wac_220811_001", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17812, 104711, 0, 10, 17812027, 0.5, "トモちゃんは真面目だね。\n私は絵の具が鎧にはねたら\nどうしようって、そればかり\n考えていたよ。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 17812, 0, "", "", 17812028, "", "", "", "", 91);
