INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 17812, "vo_wac_220811", "", 0, 17812031, "", "vo_wac_220811_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17812, 100511, 0, 10, 17812032, 0.5, "自分は、トラタイガーの\nことを考えながら描いてたッス！\n正義のヒーローへの憧れと情熱を、\nランドソルの壁に叩きつけたッス！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 17812, 0, "", "", 17812033, "", "", "", "", 91);
