INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17812, 107111, 0, 10, 17812037, 0.5, "まったく、分かっていないな！\n芸術とは感性の爆発だ、勢い任せだ！\n宴の始まりに狂喜乱舞するかの如く、\n本能のまま描くのが最良なんだぞ☆", 1, 0, 11);
