INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_wish_loop_L", 18812, 102711, 0.2, 0, 18812034, "", "wac_talk_wish_in_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 18812, "vo_wac_220821", "", 0, 18812035, "", "vo_wac_220821_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812, 102711, 0, 10, 18812036, 0.5, "クスクス……違います。\nこれはあのおかたへの愛……\n枯れることのない、永遠の愛が\nテーマですわ……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812, 0, "", "", 18812037, "", "", "", "", 91);
