INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 19112, 104911, 0, 10, 19112009, 0.5, "お姉ちゃんのお姉ちゃんによる、\nお姉ちゃん史を覆す芸術が完成したよ！\n弟くんも一目見ただけで、この絵から\nお姉ちゃんを感じてくれるよね？", 1, 0, 11);
