INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 19812, 104511, 0, 10, 19812044, 0.5, "そ、そうですね……\nドＳさんも多種多様な攻めを\n繰り出してきますけど、全部\nクウカにとっては快感ですし。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 19812, 0, "", "", 19812045, "", "", "", "", 91);
