INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23212, 102811, 0, 10, 23212022, 0.5, "ふぅ、これでできあがりね。\nみんなもすごく上手に描けてるし、\nよく頑張ったわね♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23212, 0, "", "", 23212023, "", "", "", "", 91);
