INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23212, 102311, 0, 10, 23212027, 0.5, "えへへ～、楽勝だよ♪\nもう何回か描いてるし、\n救護院でもクルミたちと\n練習してるからねー", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23212, 0, "", "", 23212028, "", "", "", "", 91);
