INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23212, 102111, 0, 10, 23212032, 0.5, "うん♪\nアヤネちゃん、すっごく\n上手になったと思うよ。\n私も頑張らなきゃ……！", 1, 0, 11);
