INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 23812, "vo_wac_221010", "", 0, 23812025, "", "vo_wac_221010_000", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812, 100811, 0, 10, 23812026, 0.5, "はぁ、思わずため息が出るよ。\nかわいいボクが、美しい絵を描く。\nただそれだけで、言葉にできないほど\n尊い場面になってしまうよね？", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812, 0, "", "", 23812027, "", "", "", "", 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812, 100811, 0.2, 1, 23812028, "", "wac_idle_wish", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_wish_loop", 23812, 104511, 0.2, 0, 23812029, "", "wac_talk_wish_in", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 23812, "vo_wac_221010", "", 0, 23812030, "", "vo_wac_221010_001", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812, 104511, 0, 10, 23812031, 0.5, "そ、そうですね……\nそんなきれいな風景の中で、\nただ一人辱めを受けている\n自分とかを想像すると……じゅるり♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812, 0, "", "", 23812032, "", "", "", "", 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812, 104511, 0.2, 1, 23812033, "", "wac_idle_wish", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_doya_loop_surprise_L", 23812, 103011, 0.2, 0, 23812034, "", "wac_talk_doya_in_surprise_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 23812, "vo_wac_221010", "", 0, 23812035, "", "vo_wac_221010_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812, 103011, 0, 10, 23812036, 0.5, "オー、まさに陰と陽！\nこれがゲージュツの分野で\nいうところの、コントラストと\nいうヤツなのでショウか？", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812, 0, "", "", 23812037, "", "", "", "", 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812, 103011, 0.2, 1, 23812038, "", "wac_idle_doya_surprise_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_sad_loop_L", 23812, 105511, 0.2, 0, 23812039, "", "wac_talk_sad_in_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 23812, "vo_wac_221010", "", 0, 23812040, "", "vo_wac_221010_003", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812, 105511, 0, 10, 23812041, 0.5, "絶対に違うと思います……\n二人とも、自分の好きなものに\n忠実なだけというか……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812, 0, "", "", 23812042, "", "", "", "", 91);
