INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 25212, 106811, 0, 10, 25212028, 0.5, "それを言うなら文武両道、\nだねリノちゃん\nでもまあ、マスターとして\nアタシも鼻が高いよ。……なんてね。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 25212, 0, "", "", 25212029, "", "", "", "", 91);
