INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26212, 103811, 0, 10, 26212022, 0.5, "ふぅ……これで完成、です。\n前よりも上手に描けたでしょうか？\nやっぱり絵を描くのって楽しいですね。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26212, 0, "", "", 26212023, "", "", "", "", 91);
