INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26212, 103311, 0, 10, 26212027, 0.5, "んだな～♪\nでも、シオシオ、体調は大丈夫か？\nあんまし無茶しちゃダメだべ？", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26212, 0, "", "", 26212028, "", "", "", "", 91);
