INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 26212, "vo_wac_221103", "", 0, 26212031, "", "vo_wac_221103_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26212, 103811, 0, 10, 26212032, 0.5, "実は、ちょっとだけ\nフラフラ～ってしてます……\nみんなでお絵描きするのが楽しくて、\nはしゃぎすぎちゃったみたいで……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26212, 0, "", "", 26212033, "", "", "", "", 91);
