INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26222, 101411, 0, 10, 26222022, 0.5, "よし、描けた。\nみんなで話し合ったりして、\nちょっと時間はかかったけど、\n悪くない出来じゃないかな？", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26222, 0, "", "", 26222023, "", "", "", "", 91);
