INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26222, 101011, 0, 10, 26222027, 0.5, "せやねぇ♪\nみんなでわいわいしながら、\nまったりと描くんも楽しかったわぁ♪\n絵にもそれが表れてます♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26222, 0, "", "", 26222028, "", "", "", "", 91);
