INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26222, 101711, 0, 10, 26222032, 0.5, "でーじ分かるさ～！\n見てるとこう、ワクワクしてきて\n思わず踊りたくなるね～\nよ～し、マコトも一緒に踊るさ～♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26222, 0, "", "", 26222033, "", "", "", "", 91);
