INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26232, 109411, 0, 10, 26232018, 0.5, "……ええと、アン。\n絵は、こんな感じでいいのかな……？\nやっぱりアンがやった方が……", 1, 0, 11);
