INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812, 103011, 0, 10, 27812031, 0.5, "おぉー、クウカがひいた曲線、\nすごくきれいデス！\nまるでウキヨエマスターみたいデスね！\nワタシにもその技、教えてクダサイ！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812, 0, "", "", 27812032, "", "", "", "", 91);
