INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_sad_loop_surprise", 27812, 105511, 0.2, 0, 27812034, "", "wac_talk_sad_in_surprise", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 27812, "vo_wac_221119", "", 0, 27812035, "", "vo_wac_221119_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812, 105511, 0, 10, 27812036, 0.5, "ニ、ニノンさんも上手でしたけど、\nクウカさんもすごい……！\nでも、クウカさんが興奮してるのは、\n違う理由のような……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812, 0, "", "", 27812037, "", "", "", "", 91);
