INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812, 105311, 0, 10, 27812041, 0.5, "うむ……もはや、何も言うまい。\nしかし共同作戦というのは悪くないな。\nこれはチームプレイの\n良い訓練になるぞ！", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812, 0, "", "", 27812042, "", "", "", "", 91);
