INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812, 100811, 0, 10, 27812046, 0.5, "ふふっ、ボクが一番\n輝いちゃって申し訳ないけどね♪\n流れる汗も太陽に照らされて、\nボクを彩ってるみたいじゃないか♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812, 0, "", "", 27812047, "", "", "", "", 91);
