INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_doya_loop", 28412, 107111, 0.2, 0, 28412030, "", "wac_talk_doya_in", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 28412, "vo_wac_221125", "", 0, 28412031, "", "vo_wac_221125_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 28412, 107111, 0, 10, 28412032, 0.5, "このクリスティーナが手伝う以上、\n粗い仕事など許さん！\nまったく、オマエたちはもう少し、\n芸術を嗜むべきだぞ♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 28412, 0, "", "", 28412033, "", "", "", "", 91);
