INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("wac_talk_arm_crossed_loop_L", 28412, 104711, 0.2, 0, 28412035, "", "wac_talk_arm_crossed_in_L", 1, "", 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 28412, "vo_wac_221125", "", 0, 28412036, "", "vo_wac_221125_003", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 28412, 104711, 0, 10, 28412037, 0.5, "クリスちゃんは相変わらずだね。\nでも、描き直したおかげで\nさらに良い絵になったと思うよ。\n私も鎧に絵の具がはねなくて一安心だ。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 28412, 0, "", "", 28412038, "", "", "", "", 91);
