INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 28412, 100511, 0, 10, 28412042, 0.5, "ジュンさん、それにみんなも、\n手伝ってくれてありがとうッス！\nおかげで、ワイルドなかっこいい絵に\n仕上がったッスよ♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 28412, 0, "", "", 28412043, "", "", "", "", 91);
