INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 35812, 107111, 0, 10, 35812022, 0.5, "むっ……おい、マツリちゃん。\nしっぽの先がペンキで汚れているぞ。\nどれ、ワタシが丁寧に拭ってやろう♪", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 35812, 0, "", "", 35812023, "", "", "", "", 91);
