INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 36912, 100311, 0, 10, 36912027, 0.5, "そう言ってもらえてなによりだよ。\n今日、こうして壁に描かれた絵も、\nきっと素敵な思い出になる。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 36912, 0, "", "", 36912028, "", "", "", "", 91);
