INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 37912, 110911, 0, 10, 37912026, 0.5, "またまた～！　そんなのアレですよ、\nそう言われてうちらがワーワー騒いでる\nところに、後ろからカリンねえさんが\nプラカード持って出てくるやつですよ。", 1, 0, 11);
