INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38012, 104611, 0, 10, 38012022, 0.5, "今回も上手にできたにゃ～♪\nあたしたちも気づけばすっかり\n絵描きの風格になったにゃ。\nこれで新しい商売でも始めるにゃ？", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 38012, 0, "", "", 38012023, "", "", "", "", 91);
