INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 38012, "vo_wac_230301", "", 0, 38012026, "", "vo_wac_230301_001", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38012, 104811, 0, 10, 38012027, 0.5, "商売って……描いた絵を売るとか？\nうーん、別に芸術家として\n有名になったわけでもないし、\nちょっと難しいような……", 1, 0, 11);
