INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38612, 100911, 0, 10, 38612036, 0.5, "いや、どうせ付け足すのならば\nこの疾風の冥姫がいかにして\n呪われし運命を克服していったか、\nその神話が分かるような壁画を……", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 38612, 0, "", "", 38612037, "", "", "", "", 91);
