INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 39512, "vo_wac_230316", "", 0, 39512031, "", "vo_wac_230316_002", "", "", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 39512, 104611, 0, 10, 39512032, 0.5, "もう既に二日酔いになってるにゃ。\n麦しゅわを飲んだことがないから、\nユカリがひたすら麦しゅわを\n求める気持ちが分かんないにゃ。", 1, 0, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 39512, 0, "", "", 39512033, "", "", "", "", 91);
