INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 39512, 104811, 0, 10, 39512037, 0.5, "大人限定ではあるけれど、手っ取り早く\n楽しい気分になれる方法なのよ……\nでも元気の前借りみたいなものだから、\nやっぱりほどほどに飲むのが一番だわ。", 1, 0, 11);
