INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 40922, 105811, 0, 10, 40922004, 0.5, "……というわけで！\nカリンさん、お待たせしました。\nランドソルの景観向上事業、\n全力全開でやり遂げましたよ☆", 1, 0, 11);
