INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 40922, 118511, 0, 10, 40922009, 0.5, "みなさん、本当にお疲れさまでした！\nこれだけ大きな壁に絵を描くのは\n大変だったと思いますが、\nとても鮮やかな景観になりましたよ♪", 1, 0, 11);
